func proxyHandler(w http.ResponseWriter, r *http.Request) {
	if !allowlist.IsAllowed(r.RemoteAddr) {
		http.Error(w, "Forbidden", http.StatusForbidden)
		return
	}

	if r.Method == http.MethodOptions {
		w.WriteHeader(http.StatusOK)
		return
	}

	if r.URL.Scheme != "https" && r.URL.Scheme != "http" {
		http.Error(w, "Invalid scheme", http.StatusBadRequest)
		return
	}

	resp, err := http.Get(r.RequestURI)
	if err != nil {
		http.Error(w, fmt.Sprintf("Failed to fetch content: %v", err), http.StatusInternalServerError)
		return
	}
	defer resp.Body.Close()

	body, err := ioutil.ReadAll(resp.Body)
	if err != nil {
		http.Error(w, fmt.Sprintf("Failed to read response body: %v", err), http.StatusInternalServerError)
		return
	}

	w.Header().Set("Content-Type", "text/plain; charset=utf-8")
	w.WriteHeader(resp.StatusCode)

	if _, err = w.Write(body); err != nil {
		log.Printf("Error writing response body: %v", err)
	}
}